import { useMemo, type PropsWithChildren } from 'react';

import Spacings from '@dynatrace/strato-design-tokens/spacings';

import { container, itemContainer } from './TooltipItem.sty.js';
import { useId } from '../../../../../../core/hooks/useId.js';
import { Divider } from '../../../../../../layouts/divider/Divider.js';
import { ChartActionsMenu } from '../../../series-action/ChartActionsMenu.js';
import { useActionSelection } from '../../context/ActionSelectionContext.js';
import type { TooltipItemProps } from '../../types/tooltip.js';

export const TooltipItem = (props: PropsWithChildren<TooltipItemProps>) => {
  const { children, showDivider, actions, defaultActions, ...rest } = props;
  const itemId = useId();

  const { selectedItemId, actionsMenuRef, updateSelectedItem } =
    useActionSelection();
  const isOpen = selectedItemId === itemId;
  const memoizedActions = useMemo(() => {
    if (isOpen && actions) {
      return actions();
    }
  }, [isOpen]);

  if (!actions && !defaultActions) {
    return (
      <>
        <div className={itemContainer} {...rest}>
          {children}
        </div>
        {showDivider && (
          <Divider
            orientation="horizontal"
            style={{ margin: `${Spacings.Size4} 0` }}
          />
        )}
      </>
    );
  }

  return (
    <ChartActionsMenu
      isOpen={isOpen}
      actions={memoizedActions}
      defaultActions={defaultActions}
      onActionClick={() => updateSelectedItem('')}
      ref={actionsMenuRef}
    >
      <button
        className={container}
        onMouseEnter={() => updateSelectedItem(itemId)}
      >
        <div className={itemContainer} {...rest}>
          {children}
        </div>
        {showDivider && (
          <Divider
            orientation="horizontal"
            style={{ margin: `${Spacings.Size4} 0` }}
          />
        )}
      </button>
    </ChartActionsMenu>
  );
};

TooltipItem['displayName'] = 'TooltipItem';
